import { useState } from "react";
import { getPatientByPhone, getAppointmentsByPhone } from "../api";

export default function SearchAppointment() {
  const [phone, setPhone] = useState("");
  const [patient, setPatient] = useState(null);
  const [appointments, setAppointments] = useState([]);

  const search = async () => {
    try {
      const p = await getPatientByPhone(phone);
      const a = await getAppointmentsByPhone(phone);

      setPatient(p.data);
      setAppointments(a.data);
    } catch (err) {
      console.log(err);
      setPatient(null);
      setAppointments([]);
    }
  };

  return (
    <div>
      <input
        placeholder="Enter mobile number"
        value={phone}
        onChange={(e) => setPhone(e.target.value)}
      />
      <button onClick={search}>Search</button>

      {patient && (
        <div>
          <h3>Patient Info</h3>
          <p>{patient.name}</p>
          <p>{patient.phone}</p>
        </div>
      )}

      <h3>Appointments</h3>
      {appointments.map((a, i) => (
        <div key={i}>
          <p>{a.date}</p>
          <p>{a.reason}</p>
        </div>
      ))}
    </div>
  );
}
